#include <iostream>
#include <fstream>
#include <string>

using namespace std;

int main() {
    string word;
    string line;
    int count = 0;

    cout << "Enter the word to search for: ";
    cin >> word;

    ifstream file("input.txt"); //change input.txt to your desired file name

    if (file.is_open()) {
        while (getline(file, line)) {
            size_t found = line.find(word); //search for the word in each line
            while (found != string::npos) { //if the word is found
                count++; //increment the count
                found = line.find(word, found + 1); //search for the next occurrence of the word in the same line
            }
        }
        file.close();
    }
    else {
        cout << "Unable to open file." << endl;
    }

    cout << "The word \"" << word << "\" appears " << count << " times in the file." << endl;

    return 0;
}

